PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
PREFIX ql: <http://qlever.cs.uni-freiburg.de/builtin-functions/>

SELECT ?durationMinutes
WHERE {
  VALUES ?year { 1977 1978 2008 2009 }
  ?edition wdt:P361 wd:Q1363275 ;
           wdt:P585 ?date ;
           wdt:P1725 wd:Q334634 ;
           wdt:P1725 wd:Q650840 .
  FILTER(YEAR(?date) = ?year)
  ?game wdt:P361 ?edition ;
        wdt:P2047 ?durationStr .
  BIND(IF(CONTAINS(?durationStr, ":"), STRBEFORE(?durationStr, ":"), "0") AS ?hoursStr)
  BIND(IF(CONTAINS(?durationStr, ":"), STRAFTER(?durationStr, ":"), ?durationStr) AS ?minutesStr)
  BIND(xsd:integer(?hoursStr) AS ?hours)
  BIND(xsd:integer(?minutesStr) AS ?minutes)
  BIND((?hours * 60) + ?minutes AS ?durationMinutes)
}
ORDER BY DESC(?durationMinutes)
OFFSET 2
LIMIT 1

