PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX ql: <http://qlever.cs.uni-freiburg.de/builtin-functions/>

SELECT ?durationMinutes
WHERE {
  VALUES ?year { 1977 1978 2008 2009 }
  ?edition wdt:P361 wd:Q1363275 ;
           wdt:P710 wd:Q334634 ;
           wdt:P710 wd:Q650840 ;
           wdt:P580 ?startDate .
  FILTER(YEAR(?startDate) = ?year)
  ?game wdt:P361 ?edition ;
        wdt:P585 ?startTime ;
        wdt:P582 ?endTime .
  BIND(ql:hour(?endTime) * 60 + ql:minute(?endTime) AS ?endInMinutes)
  BIND(ql:hour(?startTime) * 60 + ql:minute(?startTime) AS ?startInMinutes)
  BIND(?endInMinutes - ?startInMinutes AS ?durationMinutes)
  FILTER(?durationMinutes > 0)
}
ORDER BY DESC(?durationMinutes)
OFFSET 2
LIMIT 1

